class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        int result = 0;
        for (int i = 0; i < 2 * limit; i += 2) {
            int countZero = (i / 2) * zero;
            int countOne = (i / 2) * one;
            int countTwo = limit - countZero - countOne;
            result += countTwo * pow(2, countTwo);
        }
        return result % (1000000007);
    }
};
